SELECT PetType, AVG(weight) AS average_weight
FROM Pets
GROUP BY PetType;

SELECT s.Fname, s.Age
FROM Student s
JOIN Has_Pet hp ON s.StuID = hp.StuID;

SELECT DISTINCT s.Fname, s.Age
FROM Student s
INNER JOIN Has_Pet hp ON s.StuID = hp.StuID;

SELECT AVG(s.Age) AS average_age
FROM Student s
WHERE s.StuID NOT IN (SELECT DISTINCT h.StuID FROM Has_Pet h);

SELECT AVG(Age) AS average_age
FROM Student
WHERE StuID NOT IN (SELECT DISTINCT StuID FROM Has_Pet WHERE StuID IS NOT NULL);

SELECT Model FROM car_names WHERE MakeId IN (
    SELECT Id FROM cars_data WHERE Weight < (SELECT AVG(Weight) FROM cars_data)
) LIMIT 1;

SELECT CountryName AS Country
FROM countries
WHERE CountryId = '4';
